```plantuml
@startuml
title ブリッジパターン

package main {
  class main
}

package Bridge {
  class Display {
    impl
    open(arg): void
    print(arg): void
    close(arg): void
    display(arg): void
  }

  abstract class DisplayImpl {
    {abstract} raw_open(arg): void
    {abstract} raw_print(arg): void
    {abstract} raw_close(arg): void
  }

  class CountDisplay {
    multi_display(arg): void
  }

  class StringDisplayImpl {
    raw_open(arg): void
    raw_print(arg): void
    raw_close(arg): void
  }

  Display o-> DisplayImpl
  Display <|-- CountDisplay
  DisplayImpl <|-- StringDisplayImpl
}

main --> Display : Uses
main --> CountDisplay : Uses
main --> StringDisplayImpl : Create

@enduml
```
